CREATE TABLE IF NOT EXISTS `class` (
    `cid` INT AUTO_INCREMENT PRIMARY KEY,
    `cname` VARCHAR(32) CHARACTER SET utf8,
    `credit` INT,
    `dept` VARCHAR(14) CHARACTER SET utf8,
    `instructor` VARCHAR(7) CHARACTER SET utf8,
    `description` VARCHAR(161) CHARACTER SET utf8,
    `modality` VARCHAR(9) CHARACTER SET utf8,
    `seats` INT
);
